namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string CategorySlug { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace RecipeHub.Models;

public class RecipeSubmission
{
    [Required(ErrorMessage = "Title is required.")]
    [StringLength(100, ErrorMessage = "Title must be 100 characters or fewer.")]
    public string Title { get; set; } = string.Empty;

    [Required(ErrorMessage = "Category is required.")]
    public string Category { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please add at least one ingredient.")]
    [MinLength(1, ErrorMessage = "Please add at least one ingredient.")]
    public string Ingredients { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please add at least one step.")]
    [MinLength(1, ErrorMessage = "Please add at least one step.")]
    public string Steps { get; set; } = string.Empty;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new() { Id = 1, Title = "Bruschetta", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Baguette", "Tomatoes", "Basil", "Garlic", "Olive oil"],
            Steps = ["Slice and toast baguette.", "Dice tomatoes with basil and garlic.", "Drizzle with olive oil and serve."],
            AverageRating = 4.2, RatingCount = 15 },
        new() { Id = 2, Title = "Stuffed Mushrooms", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Button mushrooms", "Cream cheese", "Garlic", "Parsley", "Breadcrumbs"],
            Steps = ["Remove mushroom stems.", "Mix cream cheese, garlic, and parsley.", "Fill caps and top with breadcrumbs.", "Bake at 375°F for 20 minutes."],
            AverageRating = 4.5, RatingCount = 8 },
        new() { Id = 3, Title = "Spaghetti Carbonara", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Parmesan", "Black pepper"],
            Steps = ["Cook spaghetti al dente.", "Fry pancetta until crisp.", "Whisk eggs with parmesan.", "Toss hot pasta with pancetta, then egg mixture.", "Season with pepper and serve immediately."],
            AverageRating = 4.8, RatingCount = 42 },
        new() { Id = 4, Title = "Chicken Stir Fry", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Chicken breast", "Bell peppers", "Soy sauce", "Ginger", "Rice"],
            Steps = ["Slice chicken and vegetables.", "Stir-fry chicken until golden.", "Add vegetables and soy sauce.", "Cook rice and serve together."],
            AverageRating = 4.0, RatingCount = 23 },
        new() { Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour"],
            Steps = ["Melt chocolate and butter together.", "Whisk eggs with sugar.", "Fold in chocolate mixture and flour.", "Bake at 425°F for 12 minutes.", "Invert onto plate and serve warm."],
            AverageRating = 4.9, RatingCount = 31 },
        new() { Id = 6, Title = "Tiramisu", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = ["Ladyfingers", "Mascarpone", "Espresso", "Cocoa powder", "Eggs", "Sugar"],
            Steps = ["Dip ladyfingers in espresso.", "Beat egg yolks with sugar, fold in mascarpone.", "Layer ladyfingers and cream.", "Refrigerate 4 hours.", "Dust with cocoa before serving."],
            AverageRating = 4.7, RatingCount = 19 },
        new() { Id = 7, Title = "Mango Smoothie", Category = "Beverages", CategorySlug = "beverages",
            Ingredients = ["Mango", "Yogurt", "Honey", "Ice"],
            Steps = ["Blend all ingredients until smooth.", "Pour into glass and serve chilled."],
            AverageRating = 4.3, RatingCount = 12 },
        new() { Id = 8, Title = "Sourdough Bread", Category = "Baking", CategorySlug = "baking",
            Ingredients = ["Bread flour", "Sourdough starter", "Water", "Salt"],
            Steps = ["Mix flour, starter, and water.", "Autolyse 30 minutes.", "Add salt and fold dough every 30 min for 2 hours.", "Shape and proof overnight in fridge.", "Bake in Dutch oven at 450°F for 40 minutes."],
            AverageRating = 4.6, RatingCount = 27 },
        new() { Id = 9, Title = "Vegetable Curry", Category = "Vegetarian", CategorySlug = "vegetarian",
            Ingredients = ["Chickpeas", "Coconut milk", "Spinach", "Curry paste", "Rice"],
            Steps = ["Sauté curry paste in oil.", "Add chickpeas and coconut milk.", "Simmer 15 minutes.", "Stir in spinach until wilted.", "Serve over rice."],
            AverageRating = 4.4, RatingCount = 18 },
    ];

    private readonly Dictionary<int, List<int>> _ratings = [];

    public List<Recipe> GetRecipesByCategory(string categorySlug)
    {
        return _recipes.Where(r => r.CategorySlug == categorySlug).ToList();
    }

    public Recipe? GetRecipeById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public List<Recipe> GetAllRecipes()
    {
        return _recipes.ToList();
    }

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;

        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = [];

        _ratings[recipeId].Add(stars);

        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null)
        {
            recipe.RatingCount = _ratings[recipeId].Count + recipe.RatingCount;
            recipe.AverageRating = _ratings[recipeId].Average();
        }
    }

    public void AddRecipe(RecipeSubmission submission)
    {
        var maxId = _recipes.Max(r => r.Id);
        var categorySlug = submission.Category.ToLower().Replace(" ", "-");

        _recipes.Add(new Recipe
        {
            Id = maxId + 1,
            Title = submission.Title,
            Category = submission.Category,
            CategorySlug = categorySlug,
            Ingredients = submission.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = submission.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            AverageRating = 0,
            RatingCount = 0
        });
    }
}

@page "/recipes"
@page "/recipes/{CategorySlug}"
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>@(CategorySlug is not null ? GetCategoryName() : "All Recipes") - RecipeHub</PageTitle>

<h1>@(CategorySlug is not null ? GetCategoryName() : "All Recipes")</h1>

@if (CategorySlug is not null)
{
    <p><a href="recipes">← Back to all recipes</a></p>
}

@if (_recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">@recipe.Category</p>
                        <p class="card-text">
                            <span class="text-warning">@GetStars(recipe.AverageRating)</span>
                            <small class="text-muted">(@recipe.RatingCount ratings)</small>
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string? CategorySlug { get; set; }

    private List<Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        _recipes = CategorySlug is not null
            ? RecipeService.GetRecipesByCategory(CategorySlug)
            : RecipeService.GetAllRecipes();
    }

    private string GetCategoryName()
    {
        var first = _recipes.FirstOrDefault();
        return first?.Category ?? CategorySlug?.Replace("-", " ") ?? "Recipes";
    }

    private static string GetStars(double rating)
    {
        var fullStars = (int)Math.Round(rating);
        return new string('★', fullStars) + new string('☆', 5 - fullStars);
    }
}

@page "/recipe/{Id:int}"
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

@if (_recipe is null)
{
    <PageTitle>Recipe Not Found - RecipeHub</PageTitle>
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
    <a href="recipes">← Browse all recipes</a>
}
else
{
    <PageTitle>@_recipe.Title - RecipeHub</PageTitle>

    <p><a href="recipes/@_recipe.CategorySlug">← Back to @_recipe.Category</a></p>

    <h1>@_recipe.Title</h1>
    <p class="text-muted">Category: @_recipe.Category</p>

    <StarRating RecipeId="@_recipe.Id" />

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in _recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in _recipe.Steps)
        {
            <li class="mb-2">@step</li>
        }
    </ol>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetRecipeById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeHub.Services
@inject RecipeService RecipeService

<div class="my-3">
    <h4>Rate this recipe</h4>
    <div class="star-rating" style="font-size: 1.5rem; cursor: pointer;">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span @onclick="() => SubmitRating(star)"
                  @onmouseover="() => _hoverStar = star"
                  @onmouseout="() => _hoverStar = 0"
                  class="@(star <= (_hoverStar > 0 ? _hoverStar : _selectedStar) ? "text-warning" : "text-muted")">
                ★
            </span>
        }
    </div>
    @if (_selectedStar > 0)
    {
        <p class="text-success mt-2">You rated this recipe @_selectedStar star@(_selectedStar > 1 ? "s" : "")!</p>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int _hoverStar;
    private int _selectedStar;

    private void SubmitRating(int stars)
    {
        _selectedStar = stars;
        RecipeService.AddRating(RecipeId, stars);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>Recipe Submitted!</h4>
        <p>Thank you for sharing "<strong>@_model.Title</strong>" with the community.</p>
        <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="_model.Title" />
            <ValidationMessage For="() => _model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="_model.Category">
                <option value="">-- Select a category --</option>
                <option value="Appetizers">Appetizers</option>
                <option value="Main Courses">Main Courses</option>
                <option value="Desserts">Desserts</option>
                <option value="Beverages">Beverages</option>
                <option value="Baking">Baking</option>
                <option value="Vegetarian">Vegetarian</option>
            </InputSelect>
            <ValidationMessage For="() => _model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="_model.Ingredients" />
            <ValidationMessage For="() => _model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="_model.Steps" />
            <ValidationMessage For="() => _model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeSubmission _model = new();
    private bool _submitted;

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(_model);
        _submitted = true;
    }

    private void Reset()
    {
        _model = new();
        _submitted = false;
    }
}

