<h1>@(CategorySlug is not null ? GetCategoryName() : "All Recipes")</h1>

@if (CategorySlug is not null)
{
    <p><a href="recipes">← Back to all recipes</a></p>
}

@if (_recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">@recipe.Category</p>
                        <p class="card-text">
                            <span class="text-warning">@GetStars(recipe.AverageRating)</span>
                            <small class="text-muted">(@recipe.RatingCount ratings)</small>
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string? CategorySlug { get; set; }

    private List<Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        _recipes = CategorySlug is not null
            ? RecipeService.GetRecipesByCategory(CategorySlug)
            : RecipeService.GetAllRecipes();
    }

    private string GetCategoryName()
    {
        var first = _recipes.FirstOrDefault();
        return first?.Category ?? CategorySlug?.Replace("-", " ") ?? "Recipes";
    }

    private static string GetStars(double rating)
    {
        var fullStars = (int)Math.Round(rating);
        return new string('★', fullStars) + new string('☆', 5 - fullStars);
    }
}

